import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Project {
  id: string;
  title: string;
  description: string;
  category: string;
  imageUrl: string;
  year: string;
}

export interface ValueItem {
  title: string;
  description: string;
  icon: string;
}

export interface TeamMember {
  name: string;
  role: string;
  image: string;
  bio: string;
}

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Projects from './components/Projects';
import Process from './components/Process';
import Team from './components/Team';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState('home');

  useEffect(() => {
    const handleScroll = () => {
      const sections = ['home', 'about', 'projects', 'process', 'team'];
      const scrollPosition = window.scrollY + 100;

      for (const section of sections) {
        const element = document.getElementById(section);
        if (element) {
          const offsetTop = element.offsetTop;
          const height = element.offsetHeight;
          if (scrollPosition >= offsetTop && scrollPosition < offsetTop + height) {
            setActiveSection(section);
          }
        }
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="min-h-screen selection:bg-olive-200 selection:text-olive-900">
      <Navbar activeSection={activeSection} />

      <main>
        <section id="home">
          <Hero />
        </section>

        <section id="about" className="py-20 bg-stone-50">
          <About />
        </section>

        <section id="projects" className="py-20 bg-white">
          <Projects />
        </section>

        <section id="process" className="py-20 bg-stone-100">
          <Process />
        </section>

        <section id="team" className="py-20 bg-white">
          <Team />
        </section>
      </main>

      <Footer />
    </div>
  );
};

export default App;

import React from 'react';

interface NavbarProps {
  activeSection: string;
}

const Navbar: React.FC<NavbarProps> = ({ activeSection }) => {
  const navItems = [
    { id: 'home', label: 'Trang Chủ' },
    { id: 'about', label: 'Về Chúng Tôi' },
    { id: 'projects', label: 'Dự Án' },
    { id: 'process', label: 'Quy Trình' },
    { id: 'team', label: 'Đội Ngũ' },
  ];

  const scrollTo = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
      window.scrollTo({
        top: element.offsetTop - 80,
        behavior: 'smooth',
      });
    }
  };

  return (
    <nav className="fixed top-0 left-0 w-full z-50 bg-[#fdfbf7]/80 backdrop-blur-md border-b border-olive-100">
      <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
        <div 
          className="flex items-center space-x-2 cursor-pointer group"
          onClick={() => scrollTo('home')}
        >
          <div className="w-10 h-10 bg-[#4a5d23] rounded-full flex items-center justify-center text-white font-bold text-xl group-hover:scale-110 transition-transform">
            Q
          </div>
          <div className="flex flex-col">
            <span className="font-bold text-xl tracking-tight text-[#4a5d23] leading-none">QVP STUDIO</span>
            <span className="text-[10px] uppercase tracking-widest text-stone-500 font-medium">Visual Storytelling</span>
          </div>
        </div>

        <ul className="hidden md:flex space-x-8">
          {navItems.map((item) => (
            <li key={item.id}>
              <button
                onClick={() => scrollTo(item.id)}
                className={`text-sm font-medium transition-all relative py-2 ${
                  activeSection === item.id ? 'text-[#4a5d23]' : 'text-stone-500 hover:text-stone-800'
                }`}
              >
                {item.label}
                {activeSection === item.id && (
                  <span className="absolute bottom-0 left-0 w-full h-0.5 bg-[#4a5d23] rounded-full" />
                )}
              </button>
            </li>
          ))}
        </ul>

        <button 
          onClick={() => scrollTo('projects')}
          className="px-6 py-2 bg-[#4a5d23] text-white text-sm font-medium rounded-full hover:bg-[#3a4a1c] transition-colors shadow-lg shadow-olive-200"
        >
          Liên Hệ
        </button>
      </div>
    </nav>
  );
};

export default Navbar;

